package generators

// bridgeSecurityGeneratedTemplate renders P1 auth-enforcement probes: every
// authenticate:-protected route must reject anonymous and malformed-token
// requests with 401 BEFORE any handler logic runs.
const bridgeSecurityGeneratedTemplate = `//go:build security

// Code generated by gopernicus. DO NOT EDIT.
// This file is regenerated every time 'gopernicus generate' runs.

package {{.BridgePackage}}

import (
	"testing"
)

func TestSecurity{{.EntityName}}AuthenticationRequired(t *testing.T) {
	client := setupSecurityServer(t)
{{range .Routes}}
	t.Run("{{.Name}} rejects anonymous", func(t *testing.T) {
		{{.Call}}.RequireStatus(t, 401)
	})
{{end}}
	// Same routes with a malformed bearer token — still 401.
	client.SetBearerToken("not-a-real-token")
{{range .Routes}}
	t.Run("{{.Name}} rejects malformed token", func(t *testing.T) {
		{{.Call}}.RequireStatus(t, 401)
	})
{{end}}}
`

const bridgeSecurityBootstrapTemplate = `//go:build security

// This file is created once by gopernicus and will NOT be overwritten.

package {{.BridgePackage}}

import (
	"context"
	"os"
	"testing"
{{- if .SpecMode}}

	"github.com/stretchr/testify/require"
{{- end}}

	"{{.RepoImport}}"
	"{{.StoreImport}}"

{{- if .SpecMode}}
	"github.com/gopernicus/gopernicus/infrastructure/database/sqlite/moderncdb"
{{- else}}
	"github.com/gopernicus/gopernicus/infrastructure/database/postgres/pgxdb"
{{- end}}
	"github.com/gopernicus/gopernicus/sdk/logger"
	"github.com/gopernicus/gopernicus/workshop/testing/testauth"
	"github.com/gopernicus/gopernicus/workshop/testing/testenv"
	"github.com/gopernicus/gopernicus/workshop/testing/testhttp"
{{- if not .SpecMode}}
	"github.com/gopernicus/gopernicus/workshop/testing/testpgx"
{{- end}}
	"github.com/gopernicus/gopernicus/workshop/testing/testserver"
{{- if .SpecMode}}
	"github.com/gopernicus/gopernicus/workshop/testing/testsqlite"
{{- end}}
)

// setupSecurityServer boots the full HTTP stack for {{.EntityName}} WITH the
// real authentication/authorization middleware (via testauth), so the
// generated probes exercise enforcement. Edit it if your routes need a
// different auth setup.
func setupSecurityServer(t *testing.T) *testhttp.Client {
	t.Helper()

	if testing.Short() {
		t.Skip("skipping security test")
	}

	ctx := context.Background()
{{- if .SpecMode}}
	db := testsqlite.SetupTestSQLite(t, ctx, testsqlite.WithMigrations(migrateSecurityDB))
	store, err := {{.StorePkg}}.NewStore(db.Querier(), db.Dialect(), {{.StorePkg}}.TxRunner(db.TxRunner()))
	require.NoError(t, err)
{{- else}}
	db := testpgx.SetupTestPGX(t, ctx, testpgx.WithMigrations(migrateSecurityDB))
	store := {{.StorePkg}}.NewStore(logger.NewNoop(), db.Pool)
{{- end}}
	repo := {{.RepoPkg}}.NewRepository({{.RepoPkg}}.NewCacheStore(store, nil))

	authenticator, _ := testauth.Authenticator("securitytest")
	authorizer := testauth.Authorizer()
	bridge := NewBridge(logger.NewNoop(), repo, testserver.NewRateLimiter(), authenticator, authorizer)

	return testserver.ServeBridge(t, bridge)
}

// migrateSecurityDB applies this project's migrations to the test database.
// testenv.ProjectRoot resolves the module root, so the migrations path works
// at any test working directory.
{{- if .SpecMode}}
func migrateSecurityDB(ctx context.Context, db *moderncdb.DB) error {
	root, err := testenv.ProjectRoot()
	if err != nil {
		return err
	}
	return moderncdb.RunMigrations(ctx, db, os.DirFS(root), "{{.MigrationsDir}}")
}
{{- else}}
func migrateSecurityDB(ctx context.Context, pool *pgxdb.Pool) error {
	root, err := testenv.ProjectRoot()
	if err != nil {
		return err
	}
	return pgxdb.RunMigrations(ctx, pool, os.DirFS(root), "{{.MigrationsDir}}")
}
{{- end}}
`
